import React from 'react';
import { useToggle } from './useToggle';

export default function App() {
  const [isOn, toggle, setIsOn] = useToggle(false);

  return (
    <div style={{ padding: '2rem', fontFamily: 'system-ui, sans-serif' }}>
      <h1 style={{ marginBottom: '1rem' }}>useToggle</h1>
      <p data-testid="toggle-value" style={{ fontSize: '1.5rem', marginBottom: '1rem' }}>
        {isOn ? '✅ ON' : '❌ OFF'}
      </p>
      <div style={{ display: 'flex', gap: '0.5rem' }}>
        <button data-testid="toggle-btn" onClick={toggle}>Toggle</button>
        <button data-testid="set-true" onClick={() => setIsOn(true)}>Set True</button>
        <button data-testid="set-false" onClick={() => setIsOn(false)}>Set False</button>
      </div>
    </div>
  );
}

