import { render, screen, fireEvent } from '@testing-library/react';
import '@testing-library/jest-dom';
import React from 'react';
import { useToggle } from './useToggle';

function Harness({ initial = false }: { initial?: boolean }) {
  const [value, toggle, setValue] = useToggle(initial);
  return (
    <div>
      <span data-testid="toggle-value">{String(value)}</span>
      <button data-testid="toggle-btn" onClick={toggle}>Toggle</button>
      <button data-testid="set-true" onClick={() => setValue(true)}>True</button>
      <button data-testid="set-false" onClick={() => setValue(false)}>False</button>
    </div>
  );
}

describe('useToggle', () => {
  it('defaults to false', () => {
    render(<Harness />);
    expect(screen.getByTestId('toggle-value')).toHaveTextContent('false');
  });

  it('respects initial value', () => {
    render(<Harness initial={true} />);
    expect(screen.getByTestId('toggle-value')).toHaveTextContent('true');
  });

  it('toggles the value', () => {
    render(<Harness />);
    fireEvent.click(screen.getByTestId('toggle-btn'));
    expect(screen.getByTestId('toggle-value')).toHaveTextContent('true');
    fireEvent.click(screen.getByTestId('toggle-btn'));
    expect(screen.getByTestId('toggle-value')).toHaveTextContent('false');
  });

  it('sets to a specific value with setValue', () => {
    render(<Harness />);
    fireEvent.click(screen.getByTestId('set-true'));
    expect(screen.getByTestId('toggle-value')).toHaveTextContent('true');
    fireEvent.click(screen.getByTestId('set-false'));
    expect(screen.getByTestId('toggle-value')).toHaveTextContent('false');
  });

  it('setValue(true) when already true stays true', () => {
    render(<Harness initial={true} />);
    fireEvent.click(screen.getByTestId('set-true'));
    expect(screen.getByTestId('toggle-value')).toHaveTextContent('true');
  });
});

